}

if (!excelInfo || excelInfo.status !== 'success') {
  return [{ json: { status: 'error', message: 'Excel creation failed', details: excelInfo } }];
}

const path = excelInfo.file;

try {
  if (fs.existsSync(path)) {
    const stats = fs.statSync(path);
    return [{ json: { 
      status: 'success', 
